class Solution {
    public String maximumBinaryString(String binary) {
        int n = binary.length();
        StringBuilder result = new StringBuilder();

        for (int i = n - 1; i >= 0; i--) {
            if (binary.charAt(i) == '0' && binary.charAt(i - 1) == '0') {
                result.append('1');
            } else if (binary.charAt(i) == '1' && binary.charAt(i - 1) == '1') {
                result.append('0');
            } else {
                result.append(binary.charAt(i));
            }
        }

        return result.reverse().toString();
    }
}
